/**
 * Dogfooding script — run the lightweight organism scanner against
 * a single project and print detailed health analysis.
 *
 * Usage: npx tsx src/dogfood-organism.ts [project-path]
 * Default: scans gnosis itself
 */

import { resolve, relative } from 'path';
import {
  scanProjectLightweight,
} from './organism-topology';

const projectPath = process.argv[2]
  ? resolve(process.argv[2])
  : resolve(import.meta.dirname, '..');

const projectName = relative(resolve(projectPath, '..', '..'), projectPath) || projectPath;

console.log(`\nDogfooding: ${projectName}`);
console.log(`Path: ${projectPath}`);
console.log('='.repeat(70));

const result = scanProjectLightweight(projectName, projectPath);

console.log(`\nFiles:      ${result.fileCount}`);
console.log(`Sigma:      ${result.sigma.toFixed(4)}`);
console.log(`Health:     ${result.health}`);
console.log(`Errors:     ${result.errors.length}`);
